import{_ as i,o as t,c as o,a2 as l}from"./chunks/framework.DGDNmojq.js";const h=JSON.parse('{"title":"Vue 3 + TypeScript 设计模式","description":"Vue 3 开发中最常用的 10 种设计模式索引，涵盖组合式 API、依赖注入、插槽、状态管理、路由等核心主题。","frontmatter":{"title":"Vue 3 + TypeScript 设计模式","description":"Vue 3 开发中最常用的 10 种设计模式索引，涵盖组合式 API、依赖注入、插槽、状态管理、路由等核心主题。"},"headers":[],"relativePath":"patterns/vue-patterns.md","filePath":"patterns/vue-patterns.md","lastUpdated":1776456138000}'),a={name:"patterns/vue-patterns.md"};function r(p,e,n,s,c,d){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="vue-3-typescript-设计模式" tabindex="-1">Vue 3 + TypeScript 设计模式 <a class="header-anchor" href="#vue-3-typescript-设计模式" aria-label="Permalink to &quot;Vue 3 + TypeScript 设计模式&quot;">​</a></h1><blockquote><p>本文档涵盖了 Vue 3 开发中最常用的 10 种设计模式，所有示例均使用 TypeScript 编写。</p></blockquote><p>完整源码及详细示例请参见 <a href="https://github.com/AdaMartin18010/JavaScriptTypeScript/blob/main/docs/patterns/VUE_PATTERNS.md" target="_blank" rel="noreferrer"><code>docs/patterns/VUE_PATTERNS.md</code></a>。</p><hr><h2 id="_1-组合式-api-composition-api-模式" tabindex="-1">1. 组合式 API (Composition API) 模式 <a class="header-anchor" href="#_1-组合式-api-composition-api-模式" aria-label="Permalink to &quot;1. 组合式 API (Composition API) 模式&quot;">​</a></h2><p>在大型组件中，选项式 API 导致相关逻辑分散在不同的选项中（data、methods、computed），使得代码难以维护和复用。组合式 API 通过 <code>setup</code> 函数或 <code>&lt;script setup&gt;</code> 将相关逻辑聚合在一起，配合 <code>composables</code> 实现跨组件复用。</p><p><strong>核心要点</strong>：</p><ul><li>使用 <code>&lt;script setup&gt;</code> 简化代码</li><li>提取可复用的 composable 函数</li><li>使用 <code>ref</code> / <code>reactive</code> / <code>computed</code> 管理状态</li><li>生命周期钩子扁平化</li></ul><hr><h2 id="_2-选项式-api-最佳实践" tabindex="-1">2. 选项式 API 最佳实践 <a class="header-anchor" href="#_2-选项式-api-最佳实践" aria-label="Permalink to &quot;2. 选项式 API 最佳实践&quot;">​</a></h2><p>虽然 Vue 3 推荐使用组合式 API，但在维护遗留项目或团队协作中，仍需要使用选项式 API。掌握其最佳实践有助于平滑迁移和团队协作。</p><p><strong>核心要点</strong>：</p><ul><li>组件命名与文件组织</li><li>Props 定义与验证</li><li>事件命名规范</li><li>Mixins 的替代方案</li></ul><hr><h2 id="_3-provide-inject-依赖注入" tabindex="-1">3. Provide/Inject 依赖注入 <a class="header-anchor" href="#_3-provide-inject-依赖注入" aria-label="Permalink to &quot;3. Provide/Inject 依赖注入&quot;">​</a></h2><p>深层嵌套的组件需要通过 props 逐层传递数据，导致 prop drilling 问题。Vue 3 的 <code>provide</code> / <code>inject</code> API 提供了跨层级依赖注入的能力。</p><p><strong>核心要点</strong>：</p><ul><li>使用 Symbol 作为注入键避免命名冲突</li><li>配合 <code>computed</code> 实现响应式注入</li><li>TypeScript 类型安全注入</li><li>与组合式 API 的结合使用</li></ul><hr><h2 id="_4-自定义指令模式" tabindex="-1">4. 自定义指令模式 <a class="header-anchor" href="#_4-自定义指令模式" aria-label="Permalink to &quot;4. 自定义指令模式&quot;">​</a></h2><p>需要直接操作 DOM 实现特定功能（如焦点管理、拖拽、权限控制）时，组件化方式过于笨重。自定义指令是更轻量的解决方案。</p><p><strong>核心要点</strong>：</p><ul><li>指令生命周期钩子</li><li>参数与修饰符</li><li>TypeScript 类型定义</li><li>常见指令：v-focus、v-permission、v-debounce</li></ul><hr><h2 id="_5-渲染函数和-jsx" tabindex="-1">5. 渲染函数和 JSX <a class="header-anchor" href="#_5-渲染函数和-jsx" aria-label="Permalink to &quot;5. 渲染函数和 JSX&quot;">​</a></h2><p>模板语法在处理动态渲染逻辑、高阶组件或复杂条件渲染时能力有限。渲染函数和 JSX 提供了更灵活的编程式渲染能力。</p><p><strong>核心要点</strong>：</p><ul><li><code>h()</code> 函数的使用</li><li>JSX / TSX 配置</li><li>函数式组件</li><li>与模板语法的对比与选型</li></ul><hr><h2 id="_6-插槽-slots-高级模式" tabindex="-1">6. 插槽 (Slots) 高级模式 <a class="header-anchor" href="#_6-插槽-slots-高级模式" aria-label="Permalink to &quot;6. 插槽 (Slots) 高级模式&quot;">​</a></h2><p>需要创建高度可定制的组件，让用户能够完全控制组件的某些部分，同时保持组件的封装性。插槽是 Vue 组件组合的核心机制。</p><p><strong>核心要点</strong>：</p><ul><li>具名插槽与默认插槽</li><li>作用域插槽</li><li>动态插槽名</li><li>渲染函数中的插槽处理</li></ul><hr><h2 id="_7-状态管理-pinia-vuex" tabindex="-1">7. 状态管理 (Pinia/Vuex) <a class="header-anchor" href="#_7-状态管理-pinia-vuex" aria-label="Permalink to &quot;7. 状态管理 (Pinia/Vuex)&quot;">​</a></h2><p>多个组件需要共享状态，props 传递和事件机制变得复杂，需要集中式的状态管理方案。Vue 3 官方推荐 Pinia 作为状态管理库。</p><p><strong>核心要点</strong>：</p><ul><li>Store 定义与模块化</li><li>State / Getter / Action / Plugin</li><li>组合式 Store</li><li>SSR 兼容性</li></ul><hr><h2 id="_8-组件库设计模式" tabindex="-1">8. 组件库设计模式 <a class="header-anchor" href="#_8-组件库设计模式" aria-label="Permalink to &quot;8. 组件库设计模式&quot;">​</a></h2><p>需要设计一套可复用、可扩展的组件库，支持主题定制、类型提示和良好的开发者体验。</p><p><strong>核心要点</strong>：</p><ul><li>Config Provider 全局配置</li><li>组件样式隔离与 CSS 变量</li><li>类型安全的组件库</li><li>按需加载与 Tree Shaking</li></ul><hr><h2 id="_9-vue-3-的响应式系统原理" tabindex="-1">9. Vue 3 的响应式系统原理 <a class="header-anchor" href="#_9-vue-3-的响应式系统原理" aria-label="Permalink to &quot;9. Vue 3 的响应式系统原理&quot;">​</a></h2><p>深入理解 Vue 3 响应式系统的工作原理，以便更好地调试和优化应用性能。</p><p><strong>核心要点</strong>：</p><ul><li><code>Proxy</code> 与 <code>Reflect</code></li><li><code>ref</code> vs <code>reactive</code></li><li>依赖收集与触发</li><li>常见响应式陷阱与解决方案</li></ul><hr><h2 id="_10-vue-router-高级模式" tabindex="-1">10. Vue Router 高级模式 <a class="header-anchor" href="#_10-vue-router-高级模式" aria-label="Permalink to &quot;10. Vue Router 高级模式&quot;">​</a></h2><p>需要实现复杂的导航守卫、动态路由、路由元信息处理等高级路由功能。</p><p><strong>核心要点</strong>：</p><ul><li>导航守卫链</li><li>动态路由与路由懒加载</li><li>路由元信息</li><li>滚动行为控制</li><li>组合式 API 中的路由操作</li></ul><hr><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><ol><li><strong>入门</strong>：先掌握组合式 API 与选项式 API 最佳实践</li><li><strong>进阶</strong>：学习 Provide/Inject、插槽和自定义指令</li><li><strong>工程化</strong>：深入状态管理、组件库设计和响应式原理</li><li><strong>高级</strong>：探索渲染函数/JSX 和 Vue Router 高级模式</li></ol><hr><blockquote><p>📎 完整代码示例和详细说明请参考项目源码 <a href="https://github.com/AdaMartin18010/JavaScriptTypeScript/blob/main/docs/patterns/VUE_PATTERNS.md" target="_blank" rel="noreferrer"><code>docs/patterns/VUE_PATTERNS.md</code></a>。</p></blockquote>',58)])])}const P=i(a,[["render",r]]);export{h as __pageData,P as default};
